'use strict';
export let __workshopId='2760603383';
export var scriptProperties=createScriptProperties()
.addCheckbox({name:'use24hFormat',label:'24h',value:true})
.addCheckbox({name:'showSeconds',label:'秒',value:false})
.addText({name:'delimiter',label:':',value:':'})
.finish();

function gp(n,d){try{var v=engine.getPropertyValue(n);return v!==undefined&&v!==null?v:d}catch(e){return d}}

function applyControls(){
try{
var ca=Math.min(Math.max(gp('ca_strength',33),0),100)/100;
engine.setLayerOpacity(300,ca);
var rp=Math.min(Math.max(gp('ripple_strength',24),0),100)/100;
engine.setLayerOpacity(305,rp);
var ra=Math.min(Math.max(gp('rain_opacity',30),0),100)/100;
engine.setLayerOpacity(30,ra);
var a1=Math.min(Math.max(gp('audio1_opacity',100),0),100)/100;
var a1v=gp('audio1_visible',true);
engine.setLayerOpacity(69,a1);
engine.setLayerVisibility(69,a1v);
var a2=Math.min(Math.max(gp('audio2_opacity',100),0),100)/100;
var a2v=gp('audio2_visible',true);
engine.setLayerOpacity(112,a2);
engine.setLayerVisibility(112,a2v);
engine.setLayerVisibility(46,gp('show_clock',true));
engine.setLayerVisibility(117,gp('show_date',true));
engine.setLayerVisibility(171,gp('show_music',true));
engine.setLayerVisibility(172,gp('show_artist',true));
}catch(e){}
}

export function update(value){
applyControls();
let t=new Date();
var h=t.getHours();
if(!scriptProperties.use24hFormat){h%=12;if(h==0)h=12;}
h=('00'+h).slice(-2);
let m=('00'+t.getMinutes()).slice(-2);
value=h+scriptProperties.delimiter+m;
if(scriptProperties.showSeconds){value+=scriptProperties.delimiter+('00'+t.getSeconds()).slice(-2);}
return value;
}

