'use strict';
// Please note: Do not remove this line or asset references may break.
export let __workshopId = '3651835769';

import * as WEMath from 'WEMath';

export var scriptProperties = createScriptProperties()
    .addCheckbox({
        name: 'enableScale',
        label: 'Enable Zoom When Hovering The Cursor // Habilitar zoom al pasar el cursor',
        value: true
    })
    .addSlider({
        name: 'hoScale',
        label: 'Hover over scale multiplier // Aumento de la escala al pasar el cursor',
        value: 1.5,
        min: 0.1,
        max: 2,
        integer: false
    })
    .addSlider({
        name: 'speed',
        label: 'Scale change speed // Velocidad de cambio de escala',
        value: 10,
        min: 1,
        max: 100,
        integer: false
    })
    .finish();

let initScale, newScale, hover = false, propertyCheck = true, speed;

export function update(value) {

    // ❌ Si el checkbox está apagado → no hay efecto
    if (!scriptProperties.enableScale) {
        return value;
    }

    // ✔ Hover activo
    if (hover) {
        value = new Vec3(
            WEMath.mix(value.x, newScale.x, speed),
            WEMath.mix(value.y, newScale.y, speed),
            WEMath.mix(value.z, newScale.z, speed)
        );
    }
    // ✔ Hover desactivado → vuelve al tamaño original
    else {
        value = new Vec3(
            WEMath.mix(value.x, initScale.x, speed),
            WEMath.mix(value.y, initScale.y, speed),
            WEMath.mix(value.z, initScale.z, speed)
        );
    }

    return value;
}

export function init(value) {
    initScale = value;
    return value;
}

export function cursorEnter(event) {
    if (scriptProperties.enableScale) hover = true;
}

export function cursorLeave(event) {
    hover = false;
}

export function applyUserProperties(changedUserProperties) {

    if (!scriptProperties.enableScale) return;

    if (scriptProperties.hoScale != undefined && propertyCheck) {
        newScale = new Vec3(initScale.multiply(scriptProperties.hoScale));
        speed = scriptProperties.speed / 100;
        propertyCheck = false;
    }
}

